        "Reduce S3 timeout from 30s to align with 10s SLA (e.g., 8s per attempt)",
        "Add circuit breaker configuration for S3 calls"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database component described. S3 is the persistence layer."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
